// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.equivalence;

import java.util.Map;

import org.eclipse.rdf4j.model.BNode;
import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.TripleTerm;
import org.eclipse.rdf4j.model.Value;

/** Stable exact diagnostic rendering for RDF 1.2 terms and solution mappings. */
final class ValueRendering {
	private ValueRendering() {
	}

	static String renderBindings(Map<String, Value> bindings) {
		StringBuilder result = new StringBuilder("{");
		boolean first = true;
		for (Map.Entry<String, Value> entry : bindings.entrySet()) {
			if (!first) {
				result.append(", ");
			}
			first = false;
			result.append('?').append(entry.getKey()).append('=').append(render(entry.getValue()));
		}
		return result.append('}').toString();
	}

	static String render(Value value) {
		if (value == null) {
			return "<unbound>";
		}
		if (value instanceof IRI iri) {
			return "<" + escapeIri(iri.stringValue()) + ">";
		}
		if (value instanceof BNode bNode) {
			return "_:" + bNode.getID();
		}
		if (value instanceof Literal literal) {
			StringBuilder result = new StringBuilder();
			result.append('"').append(escapeLiteral(literal.getLabel())).append('"');
			literal.getLanguage().ifPresent(language -> result.append('@').append(language));
			if (literal.getBaseDirection() != null
					&& literal.getBaseDirection() != Literal.BaseDirection.NONE) {
				result.append("--").append(literal.getBaseDirection().name().toLowerCase());
			}
			if (literal.getLanguage().isEmpty() && literal.getDatatype() != null) {
				result.append("^^<").append(escapeIri(literal.getDatatype().stringValue())).append('>');
			}
			return result.toString();
		}
		if (value instanceof TripleTerm triple) {
			return "<<(" + render(triple.getSubject()) + " " + render(triple.getPredicate())
					+ " " + render(triple.getObject()) + ")>>";
		}
		return value.getClass().getName() + "(" + value.stringValue() + ")";
	}

	private static String escapeLiteral(String value) {
		return value.replace("\\", "\\\\")
				.replace("\"", "\\\"")
				.replace("\n", "\\n")
				.replace("\r", "\\r")
				.replace("\t", "\\t");
	}

	private static String escapeIri(String value) {
		return value.replace("\\", "\\\\")
				.replace(">", "\\u003E")
				.replace("<", "\\u003C");
	}
}
